const WINNING_LINES = [
  [[0, 0], [0, 1], [0, 2]],
  [[1, 0], [1, 1], [1, 2]],
  [[2, 0], [2, 1], [2, 2]],
  [[0, 0], [1, 0], [2, 0]],
  [[0, 1], [1, 1], [2, 1]],
  [[0, 2], [1, 2], [2, 2]],
  [[0, 0], [1, 1], [2, 2]],
  [[0, 2], [1, 1], [2, 0]],
];

function emptyBoard() {
  return [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ];
}

function move(board, row, col, player) {
  if (board[row][col]) return board;

  const nextBoard = board.map(row => [...row]);
  nextBoard[row][col] = player;

  return nextBoard;
}

function findWinner(board) {
  for (const [a, b, c] of WINNING_LINES) {
    const player = board[a[0]][a[1]];

    if (
      player &&
      player === board[b[0]][b[1]] &&
      player === board[c[0]][c[1]]
    ) {
      return player;
    }
  }

  return null;
}
